import{_ as n,I as b,o as p,c as x,a4 as i,j as r,J as s,w as t,a as l}from"./chunks/framework.EYT3XhWU.js";const S=JSON.parse('{"title":"语句填空","description":"","frontmatter":{},"headers":[],"relativePath":"行测/言语理解/语句填空.md","filePath":"行测/言语理解/语句填空.md"}'),a={name:"行测/言语理解/语句填空.md"},d={class:"details custom-block",open:"",style:{"box-sizing":"border-box",border:"1px solid rgba(0, 0, 0, 0)","border-radius":"8px",padding:"16px 16px 8px","line-height":"24px","font-size":"16px",color:"rgb(223, 223, 214)","background-color":"rgba(142, 150, 170, 0.14)",margin:"0px !important"}},g={start:"7",style:{"box-sizing":"border-box","list-style":"decimal",margin:"16px 0px",padding:"0px 0px 0px 1.25rem"}},w={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}},y={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}},_={class:"details custom-block",open:"",style:{"box-sizing":"border-box",border:"1px solid rgba(0, 0, 0, 0)","border-radius":"8px",padding:"16px 16px 8px","line-height":"24px","font-size":"16px",color:"rgb(223, 223, 214)","background-color":"rgba(142, 150, 170, 0.14)",margin:"0px !important"}},m={start:"7",style:{"box-sizing":"border-box","list-style":"decimal",margin:"16px 0px",padding:"0px 0px 0px 1.25rem"}},z={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none"}},f={class:"details custom-block",open:"",style:{"box-sizing":"border-box",border:"1px solid rgba(0, 0, 0, 0)","border-radius":"8px",padding:"16px 16px 8px","line-height":"24px","font-size":"16px",color:"rgb(223, 223, 214)","background-color":"rgba(142, 150, 170, 0.14)",margin:"0px !important"}},k={start:"7",style:{"box-sizing":"border-box","list-style":"decimal",margin:"16px 0px",padding:"0px 0px 0px 1.25rem"}},v={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}};function u(c,o,A,C,T,D){const e=b("font");return p(),x("div",null,[o[17]||(o[17]=i('<h1 id="语句填空" tabindex="-1">语句填空 <a class="header-anchor" href="#语句填空" aria-label="Permalink to “语句填空”">​</a></h1><p>字数: 6390 字 时长: 24 分钟 <strong>VIP文档</strong></p><ol><li><strong>1、考查频次</strong>：一般，一套题目中考查1-2题。</li><li><strong>2、题型特征</strong>：文段画横线空出一个句子要求填写。</li><li><strong>3、提问方式</strong>：“填入横线部分最恰当的一项是”。</li></ol><h2 id="解题思路" tabindex="-1">解题思路 <a class="header-anchor" href="#解题思路" aria-label="Permalink to “解题思路”">​</a></h2><ol><li><p><strong>1、内容上</strong>：保持话题一致。<code>“话题一致”指组成段落的句子、分句之间，有紧密的联系，围绕着一个核心话题集中地表现一个事实、场景或思想观点。</code></p></li><li><p><strong>2、结构上</strong>：分析该句子在文段中的作用。(总结/转折/过渡/其他)</p></li><li><p><strong>3、横线上</strong>：</p><ol><li><p>（1）横线在开头</p><p>:</p><ol><li>①第一种开头：应起到代表文段主旨作用，概括文段中心内容，与文段构成总分关系。</li><li>②第二种开头：跟全文没有关联，只是为了引出第二句，即引出下文，“启下”的作用。</li></ol></li><li><p>（2）横线在结尾：总结全文或提出对策（<code>结尾中的分句要与前面分句衔接，保证前后话题一致</code>）。</p></li><li><p>（3）横线在中间：在结构上是承上启下作用，也可能只 “承上” 或只 “启下” 。重点抓住前后两句话的关键词。</p></li></ol></li></ol><h2 id="例题解析" tabindex="-1">例题解析 <a class="header-anchor" href="#例题解析" aria-label="Permalink to “例题解析”">​</a></h2><p><strong>例1</strong>：（2018上海）____________，画家以手中笔墨，抒发胸中逸气，作品倾注着作者的思想和精神。中国画是通过形象、意象、兴象而达到移情言志的目的。绝似物象的绘画、绝不似物象的绘画都不是真正的艺术，唯有有感而发的“似与不似之间”的意象、兴象作品才为上乘之作。如果偏离了以情感为基础的意象、兴象理念的表述，中国画就失去了生命。中国画需要自我心灵与山水灵性的结合，才能赋予其抒情诗般的意境。</p><ol><li>填入横线处最恰当的一句是（ ）</li><li>A.中国画重视意象</li><li>B.意象是绘画的生命</li><li>C.中国画不单纯描写自然</li><li>D.中国画注重一己情感的表达</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="7" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">横线在文段开头，应起到代表文段主旨或 “启下” 的作用。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">通读文段，发现“中国画”是关键词，排除B。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">对比ACD，再次通读文段，发现 “...移情言志...” 、 “...以情感为基础...” 、 “...抒情诗般的...” ，都提到了情感， “情感” 也是关键词，所以选D。</li></ol></details><p><strong>例2</strong>：（2023广东）农村生态文明建设，____________。一是必须加速由高耗能、高污染的粗放型农业生产方式向清洁循环的集约型农业发展方式转变，加强农业科技研发与推广应用，建立全产业链绿色化农业发展模式。二是促进农业资源循环利用，积极推进农业清洁生产，提高禽畜养殖废弃物资源化利用。</p><ol><li>以下句子填入划横线处，最恰当的是（ ）。</li><li>A.必须与美丽乡村建设紧密结合</li><li>B.必须大力推进绿色循环农业发展</li><li>C.必须充分利用科技研发促进农业生产</li><li>D.必须树立 “绿水青山就是金山银山” 的价值导向</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="7" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">横线出现在文段开头，应起到代表文段主旨或 “启下” 的作用，需结合后文内容进行分析。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">后文围绕两个方面论述，一是必须转变为清洁循环的集约型农业发展方式，二是促进农业资源循环利用，积极推进农业清洁生产，这两个方面都围绕发展绿色循环农业展开，对应B项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项 “与美丽乡村建设紧密结合” 、D项 “树立价值导向” 文段均未提及，无中生有，且均偏离核心话题 “循环” ，排除；C项， “科技研发” 仅对应后文第一部分内容，表述片面，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故答案为B。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;"><code style="box-sizing:border-box;font-family:-apple-system, system-ui, &quot;Segoe UI&quot;, Roboto, Ubuntu, Cantarell, &quot;Noto Sans&quot;, sans-serif, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei&quot;, Arial;font-size:14px;width:unset;color:rgb(155, 133, 245);border-radius:4px;padding:3px 6px;background-color:rgba(101, 117, 133, 0.16);transition:color 0.25s, background-color 0.5s;">两方面是并列结构，总领全文需要概括文段中心内容</code></li></ol></details><p><strong>例3</strong>：（2021年新疆）________。然而，随着我国经济快速发展，人民生活水平日益提高，婚俗悄然“变味”。“辛辛苦苦几十年，一婚回到贫困线”不是段子，而是屡见不鲜的现实。动辄十几万到几十万不等的惊人“天价彩礼”，高攀不起的“份子钱”，一摆就是几十桌甚至上百桌的豪华婚宴，尽显低俗甚至触及法律底线的“婚闹”······凡此种种，不一而足，婚俗中的一些不正之风，打着传统文化的旗号，传播的却是不健康、不文明的文化气息。</p><ol><li>填入画横线部分最恰当的一项是：</li><li>A.最令人深恶痛绝的是无底线的低俗乃至愚俗的“婚闹”</li><li>B.文明的婚俗，是践行社会主义核心价值观的生动实现，是良好社会风尚的重要载体</li><li>C.婚俗礼仪传承千年，全国各地已形成了各具特色的婚礼习俗，也成为传统文化的重要组成部分</li><li>D.婚俗之“俗”，乃传统习俗、公序良俗之意，绝无半点庸俗、低俗的味道</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">横线出现在文段开头，需结合后文内容进行分析。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">横线后通过“然而”引导转折，指出随着经济快速发展和人民生活水平的日益提高，婚俗悄然“变味”，并举例说明。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">尾句“凡此种种”对前文进行总结，指出婚俗中存在不正之风，传播不健康、不文明的文化气息。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">因此横线不是总领全文，根据文段结构，横线后是转折，那横线的意思应该与转折后的相反，横线处应体现出婚俗“变味”之前的状态，即“婚俗”是积极的、正向的，非“不健康、不文明”的。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项体现出婚俗原本传递的价值观是积极的，而非庸俗、低俗的，当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，“最令人深恶痛绝的是无底线的低俗乃至愚俗的‘婚闹’”，没有提到“婚俗”这一话题，与后文无法构成转折，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，“社会主义核心价值观”“良好社会风尚”文段未提及，与后文衔接不当，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“全国各地已形成了各具特色的婚礼习俗”文段未提及，与后文衔接不当，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><p><strong>例4</strong>：（2021年上海）______，是一个重要的议题。某种程度上，媒体为了传播效果，通常都希望获得一种“确定性”，比如确定某种药物有效、确定“拐点”何时到来等，这样的“重磅”报道自然也会迎来更多点击率。但是，一些报道引发的连锁反应，也让我们看到：不加辨别地去追求“确定性”，并不是抚平受众焦虑的办法，反而会进一步让人们产生不安，并影响媒体的公信力。因此，对于抗疫报道来说，应当接受疫情的“不确定性”，避免因不专业、不恰当的操作导致信息焦虑。</p><ol><li>A.加强对疫情信息的筛查</li><li>B.如何避免引发信息焦虑</li><li>C.媒体不应一味地追求“确定性”</li><li>D.关于疫情的报道应该更专业</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">横线出现在文段开头，且根据“议题”可知，需填入一个表示“议题”的句子。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">后文首先提到为了传播效果，媒体希望“确定性”，紧接着通过“但是”指出问题，即不加区分的追求“确定性”会让人们产生不安。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">尾句“因此”提出对策，要接受“不确定性”，避免导致信息焦虑。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故横线处应为如何避免信息焦虑的议题，对应B项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“疫情信息的筛查”文段未体现，无中生有，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项“不应一味地追求‘确定性’”、D项“应该更专业”均为明确对策表述，而非讨论的议题，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例5</strong>：（2021浙江）上世纪70年代以来，两栖动物正经历着全球性的种群下降和物种灭绝，下降速度之快、受胁物种之广，居各陆栖脊椎动物类群之首。但奇怪的是，很长时间以来，________。因为很多两栖动物在远离人类干扰的偏远山区或自然保护区内突然消失，一些解释野生动物濒危的主流假说，如栖息地丧失、人类捕杀、气候变化等，都无法解释大量的两栖动物下降事件。因此，两栖动物的下降也曾一度被称作一场“神秘的下降”。</p><ol><li>填入画横线部分最恰当的一项是：</li><li>A.非野生的两栖动物种群并未出现明显下降</li><li>B.气候、环境等自然因素并没有发生剧烈变化</li><li>C.科学家找不到导致两栖动物种群快速下降的原因</li><li>D.全球两栖动物种群下降现象并未引起科学家的重视</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">横线在文段中间，需考虑与前后文的衔接。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">前文介绍两栖动物出现了种群下降速度快、物种灭绝范围广的现象。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">接着出现转折关联词“但”引导横线内容。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">横线后通过“因为”引导原因，介绍很多两栖动物都是突然消失的，且主流假说都无法解释它们的下降事件，又通过“因此”总结两栖动物的下降是一种“神秘的下降”。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故横线处要表达的是并未发现能说明两栖动物种群快速下降的原因，C项当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，“非野生的两栖动物”范围缩小，文段讨论的核心话题是“两栖动物”，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，“气候、环境等自然因素”偏离文段核心话题，文段讨论的是“两栖动物的下降”，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，“并未引起科学家的重视”文段未提及，无中生有，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为C。</li></ol></details><p><strong>例6</strong>：（2021国家）虽然物质生产是社会生活的基础，但上层建筑也可以反作用于经济基础，生产力和生产关系、经济基础和上层建筑之间有着十分复杂的关系，有着作用和反作用的现实过程，并不是单线式的简单决定和被决定逻辑。世界上的事物总是有着这样那样的联系，不能孤立地静止地看待事物发展，________。正所谓“有无相生，难易相成，长短相形，高下相倾，音声相和，前后相随”。在观察社会发展时，一定要注意这种决定和被决定、作用和反作用的有机联系。对生产力标准必须全面准确理解，不能绝对化，不能撇开生产关系、上层建筑来理解生产力标准。</p><ol><li>填入画横线部分最恰当的一项是：</li><li>A.广袤的自然界是如此，丰富的精神世界也是如此</li><li>B.每一个事物各部分、要素之间都存在联系</li><li>C.否则往往会出现盲人摸象、以偏概全的问题</li><li>D.任何事物都与周围的其他事物相互联系着</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">横线位于文段中间，需要结合上下文内容进行分析。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">前文指出物质生产是基础，然后通过转折关联词“但”强调上层建筑可以反作用于经济基础，并且论述了生产力和生产关系、经济基础和上层建筑的关系比较复杂。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">接着论述世界上的事物是联系的，不能孤立静止地看待。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">横线后的内容强调了万事万物相辅相成、相互依存，要全面理解，不能绝对化。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">可知，文段的逻辑是提出问题—分析问题—解决问题，首先论述万事万物不能孤立看待，接着分析孤立看待的后果，结尾则针对上文的问题给出对策即要全面看待，那么横线应填的内容为孤立看待事物的后果或者影响，对应C项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，体现不出孤立看待的结果，且与后文联系不紧密，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，“都存在联系”与横线前的内容“不能孤立地静止地看待”衔接不恰当，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，与横线前内容“世界上的事物总是有着这样那样的联系”表意重复，衔接不当，体现不出孤立看待的结果，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为C。</li></ol></details><p><strong>例7</strong>：（2021安徽）提到一座城市，人们往往会想到具有代表性的文化地标：600岁的紫禁城见证着北京城的过往，拓荒牛雕塑标记着深圳的开拓进取……城市文化地标______________，成为一个城市的精神和文化象征，与人们产生紧密的情感连接、文化认同。文化地标是一个地方的文化名片，在传播城市形象方面有巨大的流量效应。近年来，文化旅游市场持续升温，各类文化地标成为热门参观地、网红打卡地。</p><ol><li>填入划横线部分最恰当的一句是：</li><li>A.大都强调人文景观与自然环境和谐共生，以形神兼备的呈现方式</li><li>B.或深植于历史文化，或投射着时代风貌，以鲜明独特的符号形象</li><li>C.不是凭借炫目奇特的视觉效果，或各类时髦文化元素的简单堆砌</li><li>D.承载着无法替代的人文价值，满足着公众的审美旨趣和美好期待</li></ol>',26)),r("details",d,[r("ol",g,[o[4]||(o[4]=r("li",{style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none"}},"横线出现在文段中间，需考虑与前后文的衔接。",-1)),r("li",w,[s(e,{color:"#fc5531",style:{"box-sizing":"border-box"}},{default:t(()=>[...o[0]||(o[0]=[l("横线前",-1)])]),_:1}),o[1]||(o[1]=l("文引出城市文化地标的话题，点出城市文化地标具有代表性，见证着一个地方的过去，标记着一个地方的风格。",-1))]),r("li",y,[s(e,{color:"#fc5531",style:{"box-sizing":"border-box"}},{default:t(()=>[...o[2]||(o[2]=[l("横线后",-1)])]),_:1}),o[3]||(o[3]=l("指出城市文化地标是一个能让人们产生城市内情感连接、文化认同的精神、文化象征，是一个地方的名片，并举例说明当下很多城市文化地标成为名片的例子。",-1))]),o[5]||(o[5]=i('<li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">因此横线处要承接前后文，表达城市文化地标代表了一个城市的过去及风格，且城市文化地标是一个具有城市地方特色的名片的语义，对应B项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，“自然环境”无中生有，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“视觉效果”“各类时髦文化元素”无中生有，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，“满足着公众的审美旨趣和美好期待”无中生有，且没有指出城市文化地标“是一个地方的文化名片”的独特象征地位，无法和后文衔接，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">选B。</li>',5))])]),o[18]||(o[18]=r("p",null,[r("strong",null,"例8"),l("：（2019国考）中星16号是我国首颗成功发射的高通量通信卫星。在这颗通信卫星上，首次使用了Ka频段宽带通信技术。卫星容量其实就像公路一样，原来通信卫星的C频段以及Ku频段最多只能容纳两辆车同时前进，所能运载的货物（也就是信息数据）是有限的。但是Ka频段的卫星容量则要大很多，它可以同时行驶10辆或者更多的汽车。这项技术的突破，______，特别是在地面通信网络无法覆盖的地区，以及飞机、高铁、轮船等交通工具上，都可以实现宽带通信。")],-1)),o[19]||(o[19]=r("ol",null,[r("li",null,"填入画横线部分最恰当的一句是："),r("li",null,"A.意味着未来通过通信卫星可以随时随地实现宽带上网"),r("li",null,"B.预示着我国自主研发技术已打破国外垄断通信的局面"),r("li",null,"C.在真正意义上实现了自主通信卫星宽带的广泛应用"),r("li",null,"D.填补了我国通信卫星在多频段通信技术领域的空白")],-1)),r("details",_,[r("ol",m,[r("li",z,[o[7]||(o[7]=l("横线处于一个长句当中，需考虑与前后文的衔接，",-1)),s(e,{color:"#fc5531",style:{"box-sizing":"border-box"}},{default:t(()=>[...o[6]||(o[6]=[l("发现后文有 “特别是在......” 这样的字眼，所以它和长句的后半部分意思高度相关，“启下”作用明显",-1)])]),_:1}),o[8]||(o[8]=l("。",-1))]),o[9]||(o[9]=i('<li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">横线后主要讲的是“不同的地区和场所都可以实现宽带通信”。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项的“随时随地”和“不同的地区和场所都可以实现宽带通信”更贴切。选A。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，“自主研发技术”与文段核心话题不一致，文段所述话题为“高通量通信卫星宽带通信”，且“已打破国外垄断通信的局面”文中并未提及，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项“真正意义上实现了自主通信卫星宽带的广泛应用”意为之前并未实现“自主”通信卫星宽带应用，但文段仅指出利用“Ka频段”通量更高，有利宽带通信，并未说明以往我国需要依赖国外技术，不能自主通信，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，“多频段通信技术”与文段核心话题不一致，文段围绕卫星可以实现“高通量”通信，及其所带来的好处展开，并非围绕频段的多与少展开，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为A。</li>',6))])]),o[20]||(o[20]=i('<p><strong>例9</strong>：（2018国考）进行骨髓移植的前提条件是有配型成功的捐赠者。双胞胎配型成功几率最高，兄弟姐妹也有可能。但在中国，20世纪70年代到现在，大多数都是独生子女，有兄弟姐妹且能配型成功的概率也非常低。另外，父母和子女之间骨髓配型成功的概率非常低，几乎为零。因此，绝大多数患者都必须依赖不认识的志愿者配型。非亲缘关系骨髓配型成功的几率只有几十万至几百万分之一，_______ 。</p><ol><li>填入画横线部分最恰当的一句是：</li><li>A.即使这样，骨髓移植仍是大多数血液疾病患者的唯一希望</li><li>B.如果冒着风险使用不完美的配型，成功率自然会大为降低</li><li>C.骨髓库里志愿者样本的多少，直接决定着病人找到合适配型的几率</li><li>D.志愿者捐献固然很重要，国家相关政策的落实和执行也是当务之急</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="7" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">横线出现在文段结尾，需与上文话题保持一致。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">后文通过“因此”总结上文，&quot;绝大多数患者都必须依赖不认识的志愿者配型&quot; 为关键句， “志愿者” 是关键词。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项不包含 “志愿者” ，排除A。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，不包含 “志愿者” ，排除B。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C和D都讲到了 “志愿者” ，但D项的关注点在于 “国家相关政策” ，前文并没有涉及 “国家政策” ，所以排除D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项提到了 “志愿者样本” 和 “合适配型” ，既和 “志愿者” 关键词对应，也和前文提到的 “配型成功” 相对应，选C。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为C。</li></ol></details><p><strong>例10</strong>：（2018事业单位联考）塑料在海洋环境中引发了越来越多的担忧，因为它们可在海洋中持续存在并对海洋及其生物产生影响，甚至可能危及人类。塑料碎片风化后分裂成小颗粒物，就连海洋的小型无脊椎动物都可能摄取。这么小的颗粒物难以追踪来源，也很难从海洋环境中清除。因此，______。</p><ol><li>填入画横线部分最恰当的一句是（ ）。</li><li>A.应该立即采取行动限制一次性塑料制品的使用</li><li>B.缓解塑料对海洋危害的最有效策略是减少塑料排放</li><li>C.只要确认了小颗粒物的主要来源就可以根治海洋污染</li><li>D.塑料危害造成的全球环境破坏主要是缘于管理不善</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">横线在文段结尾，且由“因此”引导，故所填内容为前文的总结。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">文段首先介绍“塑料在海洋环境中引起了担忧”，接着阐述引起担忧的原因，而后说明塑料分裂所形成的颗粒物难以追踪来源，也难以清除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">文段为提出问题-分析问题的结构，故横线处的总结应为解决问题的对策，因为难以清除，故应该在进入海洋之前采取相应措施，即减少排放，对应B项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，文段核心话题为“海洋中的塑料”，“一次性塑料制品”范围太大，偏离核心话题，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，根据“这么小的颗粒物难以追踪来源，也很难从海洋环境中清除”可知，选项内容与文意矛盾，且对应一个方面，表述片面，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，“管理不善”与前文话题不一致，无中生有，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例11</strong>：（2021山东）早期人们对质量的认识并不清晰，质量管理专家给出的质量定义也不统一，比较有代表性的定义是“质量是产品符合规定要求的程度”，这是从生产角度来定义的质量，即强调产品要达到规定要求或标准。20世纪60年代美国质量管理专家提出，质量是产品的适应性，强调产品要适合用户的使用需要，任何产品如果不能满足顾客需要，不管它多么符合产品标准，也不是好的质量，这是人们首次从用户的角度认识和定义质量。_________________，这是质量观的一次重大转变。</p><ol><li>填入画横线部分最恰当的一项是：</li><li>A.从满足生产需求转变到供给需求</li><li>B.从对产品的保量要求转变到保质要求</li><li>C.从强调产品转变到强调服务</li><li>D.从关注生产方转变到关注需求方</li></ol>',8)),r("details",f,[r("ol",k,[o[15]||(o[15]=r("li",{style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none"}},"横线位于文段结尾，是对前文的总结。",-1)),r("li",v,[o[12]||(o[12]=l("前文首先指出早期人们对质量认识不清晰，",-1)),s(e,{color:"#fc5531",style:{"box-sizing":"border-box"}},{default:t(()=>[...o[10]||(o[10]=[l("专家是从生产角度定义质量",-1)])]),_:1}),o[13]||(o[13]=l("，强调产品要达到规定要求或标准。接着指出20世纪60年代美国专家提出产品要适合用户的需求，即",-1)),s(e,{color:"#fc5531",style:{"box-sizing":"border-box"}},{default:t(()=>[...o[11]||(o[11]=[l("从用户角度认识和定义质量",-1)])]),_:1}),o[14]||(o[14]=l("。",-1))]),o[16]||(o[16]=i('<li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">由此可知，横线前主要强调人们对质量的定义从生产方的角度转向用户需求的角度，即 “从关注生产方转变到关注需求方” ，对应D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，偷换概念， “供给需求” 是产品的供给方的需求，而文段说的是 “从用户的角度认识和定义质量” ，是关注用户的需求，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项， “保量要求” 无中生有，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，文段说的是 “适合用户的使用需要” “从用户的角度认识和定义质量” ，即关注需求方，选项中的 “服务” 只是用户需求中的一个方面，范围缩小，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">选D。</li>',5))])]),o[21]||(o[21]=i('<p><strong>例12</strong>：（2021上海）我们常说，群众的眼睛是雪亮的，其实包含两层意思：一层是，工作做得如何、问题改得如何，群众有切身体验，往往再清楚不过；另一层则是，问题的症结出现在哪里，有怎样的改进办法，群众也往往看得很清楚。从前者来看，在工作中引入群众监督，让群众来“鉴定”整改落实成效，能让工作更好对接群众需求；就后者而言，_______。</p><ol><li>填入横线处最恰当的一项是：</li><li>A.群众监督应覆盖工作全过程，让结果更加服众</li><li>B.群众监督的过程也是一个集思广益的过程，能推动问题更好地得到解决</li><li>C.工作中多倾听群众意见、多了解群众期待、多汲取群众智慧，并将之体现到整改方案中</li><li>D.群众的意见建议比领导的更有针对性和可操作性</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">横线出现在文段结尾，根据前文可知，文段通过两个并列结构对“群众的眼睛是雪亮的”进行解释，包含两层意思。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">根据横线前“就后者而言”可知，横线处对应第二层意思，即“问题的症结出现在哪里，有怎样的改进办法，群众也往往看得很清楚”，强调群众可以帮助解决问题。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项“能推动问题更好地得到解决”能体现群众帮助解决问题，当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，与群众帮忙解决问题无关，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“工作中多倾听群众意见、多了解群众期待、多汲取群众智慧”即体现出要在工作中引入群众监督，对应前文的第一层意思，但横线处应对应第二层意思，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，文段并未对群众和领导的意见建议进行对比，故无中生有，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details>',3))])}const P=n(a,[["render",u]]);export{S as __pageData,P as default};
